function openTenantSelector() {
    $('#tenantSelectorModal').modal('show');

    fetch('/api/m365/tenants')
        .then(res => res.json())
        .then(data => {
            const container = document.getElementById("tenantList");
            container.innerHTML = ""; 

            if (data.length === 0) {
                container.innerHTML = "<div class='alert alert-info'>No tenants available.</div>";
                return;
            }

            data.forEach(t => {
                const btn = document.createElement("button");
                btn.className = "list-group-item list-group-item-action";
                btn.innerText = t.display_name + " (" + t.tenant_id + ")";
                btn.onclick = function () {
                    window.location.href = "/m365/auth?tenant_id=" + encodeURIComponent(t.tenant_id);
                };
                container.appendChild(btn);
            });
        });
}
